import 'dart:typed_data';
import 'dart:convert';

String verificFoto(Map<String, dynamic> fotos) {
  if (fotos['foto'] != null) {
    return fotos['foto'];
  } else {
    return getImagepadrao();
  }
}

showBase64ImageDefald(base64String) {
  if (base64String != null) {
    UriData? data = Uri.parse(base64String).data;
    Uint8List myImage = data!.contentAsBytes();
    return myImage;
  } else {
    String? image = getImagepadrao();

    UriData? data = Uri.parse(image).data;
    Uint8List myImage = data!.contentAsBytes();
    return myImage;
  }
}

Uint8List decodeBase64Image(String base64String) {
  // Verifica e remove o prefixo, se existir
  if (base64String.startsWith("data:image")) {
    base64String = base64String.split(',').last;
  }
  return base64Decode(base64String);
}

String getImagepadrao() {
  return "data:image/png;base64,";
}
